<?php
namespace App\Domain\Repayments\Actions;
use App\Enums\ChargeCalculationType;use App\Enums\InstallmentStatus;use App\Models\LoanPenaltyApplication;use App\Models\LoanRepaymentInstallment;
class ApplyLatePenalties{public function execute():int{$applied=0;LoanRepaymentInstallment::query()->with('loan.product.charges')->where('status',InstallmentStatus::Overdue->value)->chunkById(100,function($installments)use(&$applied){foreach($installments as $installment){$basis=$installment->principal_due_minor+$installment->interest_due_minor+$installment->charges_due_minor-$installment->amount_paid_minor;foreach($installment->loan->product->charges->where('application_timing','late_repayment')->where('is_active',true) as $charge){$recurrence=$charge->configuration['recurrence']??'one_time';$date=$recurrence==='one_time'?$installment->overdue_since:today();if(LoanPenaltyApplication::query()->where('loan_repayment_installment_id',$installment->id)->where('charge_id',$charge->id)->when($recurrence==='one_time',fn($q)=>$q,fn($q)=>$q->whereDate('assessment_date',$date))->exists())continue;$amount=$charge->calculation_type===ChargeCalculationType::Fixed?$charge->fixed_amount_minor:intdiv(max(0,$basis)*$charge->rate_basis_points,10000);if($charge->minimum_amount_minor!==null)$amount=max($amount,$charge->minimum_amount_minor);if($charge->maximum_amount_minor!==null)$amount=min($amount,$charge->maximum_amount_minor);if($amount<=0)continue;LoanPenaltyApplication::query()->create(['loan_id'=>$installment->loan_id,'loan_repayment_installment_id'=>$installment->id,'charge_id'=>$charge->id,'assessment_date'=>$date,'basis_amount_minor'=>max(0,$basis),'amount_minor'=>$amount,'rule_snapshot'=>$charge->toArray()]);$installment->increment('penalties_due_minor',$amount);$installment->loan->increment('outstanding_minor',$amount);$applied++;}}});return $applied;}}
